const { day, leads, config } = $input.first().json.body;

const freq = config.reminders.frequencyDays;
const maxR = config.reminders.maxReminders;

let idCounter = Date.now();
function uid() { return `a${idCounter++}`; }
function ts() { return new Date().toISOString(); }

function budgetScore(b) { return b > 2000 ? 10 : b >= 500 ? 6 : 3; }
function intentScore(s) { return s === 'high' ? 9 : s === 'medium' ? 6 : 3; }
function timelineScore(d) { return d <= 7 ? 10 : d <= 21 ? 6 : 3; }

function computeScore(lead) {
  const bs = budgetScore(lead.formInputs.budget);
  const is = intentScore(lead.intentSignal);
  const ts2 = timelineScore(lead.formInputs.timelineDays);
  const { budgetWeight, intentWeight, timelineWeight } = config.scoring;
  const raw = (bs * budgetWeight + is * intentWeight + ts2 * timelineWeight) / 100;
  const score = Math.round(raw);
  return { score, classification: score >= 7 ? 'Hot' : score >= 4 ? 'Warm' : 'Cold' };
}

const allActions = [];
const leadUpdates = {};

const hotLead = [...leads].filter(l => l.score >= 7).sort((a, b) => a.registeredOnDay - b.registeredOnDay)[0];
const warmLead = [...leads].filter(l => l.score >= 4 && l.score < 7).sort((a, b) => a.registeredOnDay - b.registeredOnDay)[0];

for (const lead of leads) {
  const rel = day - lead.registeredOnDay;
  const actions = [];
  const updates = {};

  if (rel === 1) {
    const { score, classification } = computeScore(lead);
    updates.score = score;
    updates.classification = classification;
    updates.status = 'Contacted';

    actions.push({ id: uid(), day, type: 'email_sent', leadId: lead.id, leadName: lead.name, actor: 'system', summary: `Onboarding email sent to ${lead.name}`, detail: { channel: 'Email', subject: `Welcome — let's talk about your project`, body: `Hi ${lead.name},\n\nThanks for reaching out! Based on your requirements (budget $${lead.formInputs.budget}, timeline ${lead.formInputs.timelineDays} days), we think we can deliver real results.\n\nI'd love to understand your goals better. Book a quick call or reply here.\n\n— ${lead.assignedRep}` }, timestamp: ts() });
    actions.push({ id: uid(), day, type: 'score_update', leadId: lead.id, leadName: lead.name, actor: 'ai', summary: `Lead scored ${score}/10 — ${classification}`, detail: { score, classification, weights: config.scoring, rationale: `Budget $${lead.formInputs.budget} (${budgetScore(lead.formInputs.budget)}/10), Intent ${lead.intentSignal} (${intentScore(lead.intentSignal)}/10), Timeline ${lead.formInputs.timelineDays}d (${timelineScore(lead.formInputs.timelineDays)}/10)` }, timestamp: ts() });
    actions.push({ id: uid(), day, type: 'rep_assigned', leadId: lead.id, leadName: lead.name, actor: 'team', summary: `${lead.assignedRep} assigned to ${lead.name}`, detail: { rep: lead.assignedRep, note: `Assigned based on availability. ${classification} lead — ${score}/10.` }, timestamp: ts() });

    if (score >= 4) {
      actions.push({ id: uid(), day, type: 'proposal_sent', leadId: lead.id, leadName: lead.name, actor: 'team', summary: `${lead.assignedRep} mailed proposal to ${lead.name}`, detail: { rep: lead.assignedRep, subject: 'Project Proposal — CloseIt Automation', body: `Hi ${lead.name},\n\nGreat to connect! I've put together a quick scope based on your brief.\n\nBudget: $${lead.formInputs.budget} | Timeline: ${lead.formInputs.timelineDays} days\n\nLet me know if you'd like to discuss further.\n\n— ${lead.assignedRep}` }, timestamp: ts() });
    }

    updates.nextReminderDay = day + freq;
  }

  const isHotReplyDay = hotLead && lead.id === hotLead.id && rel === 3;
  const isWarmReplyDay = warmLead && lead.id === warmLead.id && rel === 5;
  const isHotCloseDay = hotLead && lead.id === hotLead.id && rel === 5;

  if (isHotReplyDay) {
    actions.push({ id: uid(), day, type: 'reply_received', leadId: lead.id, leadName: lead.name, actor: 'customer', summary: `${lead.name} replied: "Ready to move — can we jump on a call?"`, detail: { from: lead.email, body: `Hi! This looks exactly like what we need. Can we schedule a call this week? We're ready to move fast on this.` }, timestamp: ts() });
    actions.push({ id: uid(), day, type: 'email_sent', leadId: lead.id, leadName: lead.name, actor: 'ai', summary: `AI drafted reply sent to ${lead.name}`, detail: { subject: 'Re: Project Proposal', body: `Hi ${lead.name},\n\nAbsolutely — I've sent a booking link. Looking forward to connecting and getting things moving.\n\n— ${lead.assignedRep} (via CloseIt AI)` }, timestamp: ts() });
    actions.push({ id: uid(), day, type: 'meeting_scheduled', leadId: lead.id, leadName: lead.name, actor: 'system', summary: `Discovery call booked with ${lead.name}`, detail: { date: `Day ${day + 1}`, duration: '30 min', rep: lead.assignedRep, nudge: true }, timestamp: ts() });
    updates.status = 'Meeting Scheduled';
    updates.nextReminderDay = null;
  }

  if (isHotCloseDay && !isWarmReplyDay) {
    actions.push({ id: uid(), day, type: 'call_logged', leadId: lead.id, leadName: lead.name, actor: 'team', summary: `${lead.assignedRep} completed discovery call with ${lead.name}`, detail: { rep: lead.assignedRep, notes: `Strong fit. ${lead.name} confirmed budget and timeline. Proceeding to agreement.` }, timestamp: ts() });
    actions.push({ id: uid(), day, type: 'closed_won', leadId: lead.id, leadName: lead.name, actor: 'team', summary: `🎉 ${lead.name} closed won by ${lead.assignedRep}`, detail: { rep: lead.assignedRep, value: `$${lead.formInputs.budget}`, note: 'Agreement signed. Onboarding starts next week.' }, timestamp: ts() });
    updates.status = 'Closed Won';
    updates.nextReminderDay = null;
  }

  if (isWarmReplyDay && !isHotCloseDay) {
    actions.push({ id: uid(), day, type: 'reply_received', leadId: lead.id, leadName: lead.name, actor: 'customer', summary: `${lead.name} replied: "Interested but swamped — check back next week"`, detail: { from: lead.email, body: `Hey, I'm interested but things are hectic right now. Can you follow up with me in a week or so?` }, timestamp: ts() });
    actions.push({ id: uid(), day, type: 'email_sent', leadId: lead.id, leadName: lead.name, actor: 'ai', summary: `AI replied — reminder clock reset for ${lead.name}`, detail: { subject: 'Re: Checking In', body: `Understood ${lead.name} — no rush at all. I'll check back in a week. In the meantime, here's a quick overview of what we'd build for you.\n\n— ${lead.assignedRep} (via CloseIt AI)` }, timestamp: ts() });
    updates.remindersSent = 0;
    updates.nextReminderDay = day + freq;
    updates.status = 'Replied';
  }

  const skipReminder = isHotReplyDay || isWarmReplyDay || isHotCloseDay ||
    ['Meeting Scheduled', 'Closed Won', 'Closed Lost', 'Nurture'].includes(lead.status);

  if (!skipReminder && lead.nextReminderDay === day && lead.remindersSent < maxR) {
    const reminderNum = lead.remindersSent + 1;
    actions.push({
      id: uid(), day, type: 'email_sent', leadId: lead.id, leadName: lead.name, actor: 'ai',
      summary: `Follow-up #${reminderNum} sent to ${lead.name} (AI-drafted)`,
      detail: {
        subject: reminderNum === 1 ? `Quick check-in — ${lead.name}` : `Last note from us — ${lead.name}`,
        body: reminderNum === 1
          ? `Hi ${lead.name},\n\nJust checking in — did you get a chance to review the proposal? Happy to answer any questions.\n\n— ${lead.assignedRep} (via CloseIt AI)`
          : `Hi ${lead.name},\n\nThis is our final note for now. If the timing isn't right, no worries — we'll be here when you're ready.\n\n— ${lead.assignedRep} (via CloseIt AI)`
      },
      timestamp: ts()
    });
    updates.remindersSent = lead.remindersSent + 1;
    updates.lastActionDay = day;

    if (lead.remindersSent + 1 >= maxR) {
      updates.status = 'Nurture';
      updates.nextReminderDay = null;
      actions.push({ id: uid(), day, type: 'moved_to_nurture', leadId: lead.id, leadName: lead.name, actor: 'system', summary: `${lead.name} moved to Nurture — max follow-ups reached`, detail: { reason: `${maxR} follow-ups sent with no response. Sequence paused.` }, timestamp: ts() });
    } else {
      updates.nextReminderDay = day + freq;
      updates.status = 'Awaiting Reply';
    }
  }

  allActions.push(...actions);
  if (Object.keys(updates).length > 0) leadUpdates[lead.id] = updates;
}

return [{ json: { day, actions: allActions, leadUpdates } }];

// Split the actions array into individual items for Sheets append
const { day, actions, leadUpdates } = $input.first().json;

if (!actions || actions.length === 0) {
  // No actions — return a dummy item to keep the flow going
  return [{ json: { _noActions: true, day, leadUpdates } }];
}

return actions.map(action => ({
  json: {
    lead_id: action.leadId,
    day: action.day,
    action_type: action.type,
    actor: action.actor,
    summary: action.summary,
    detail_json: JSON.stringify(action.detail || {}),
    timestamp: action.timestamp
  }
}));
